body:
Fix an inconsistency between the handling of read ports and read-write ports when running HWMemSimImpl with the "ignore-read-enable" option (firtool option "-ignore-read-enable-mem").  After #5700, this would cause the enable line of a read-write read port to have no effect. I.e., the memory would always read even if not enabled.  Change this to align with the behavior of read ports where the memory always returns the last read address.

#### Example

Input:

```
circuit Foo:
  module Foo:
    input r: {addr: UInt<3>, en: UInt<1> clk: Clock, flip data: UInt<32>}
    input rw: {addr: UInt<3>, en: UInt<1> clk: Clock, flip rdata: UInt<32>, wmode: UInt<1>, wdata: UInt<32>, wmask: UInt<1>}

    mem memory:
      data-type => UInt<32>
      depth => 8
      reader => r
      readwriter => rw
      read-latency => 1
      write-latency => 1
      read-under-write => undefined

    memory.r <= r
    memory.rw <= rw
```

Old output:

```verilog
module memory_8x32(
  input  [2:0]  R0_addr,
  input         R0_en,
                R0_clk,
  input  [2:0]  RW0_addr,
  input         RW0_en,
                RW0_clk,
                RW0_wmode,
  input  [31:0] RW0_wdata,
  output [31:0] R0_data,
                RW0_rdata
);

  reg [31:0] Memory[0:7];
  reg [2:0]  _GEN;
  always @(posedge R0_clk) begin
    if (R0_en)
      _GEN <= R0_addr;
  end // always @(posedge)
  reg [2:0]  _GEN_0;
  reg        _GEN_1;
  reg        _GEN_2;
  always @(posedge RW0_clk) begin
    _GEN_0 <= RW0_addr;
    _GEN_1 <= RW0_en;
    _GEN_2 <= RW0_wmode;
    if (RW0_en & RW0_wmode)
      Memory[RW0_addr] <= RW0_wdata;
  end // always @(posedge)
  assign R0_data = Memory[_GEN];
  assign RW0_rdata = Memory[_GEN_0];
endmodule
```

New output:

```verilog
module memory_8x32(
  input  [2:0]  R0_addr,
  input         R0_en,
                R0_clk,
  input  [2:0]  RW0_addr,
  input         RW0_en,
                RW0_clk,
                RW0_wmode,
  input  [31:0] RW0_wdata,
  output [31:0] R0_data,
                RW0_rdata
);

  reg [31:0] Memory[0:7];
  reg [2:0]  _GEN;
  always @(posedge R0_clk) begin
    if (R0_en)
      _GEN <= R0_addr;
  end // always @(posedge)
  reg [2:0]  _GEN_0;
  reg        _GEN_1;
  always @(posedge RW0_clk) begin
    if (RW0_en)
      _GEN_0 <= RW0_addr;
    _GEN_1 <= RW0_wmode;
    if (RW0_en & RW0_wmode)
      Memory[RW0_addr] <= RW0_wdata;
  end // always @(posedge)
  assign R0_data = Memory[_GEN];
  assign RW0_rdata = Memory[_GEN_0];
endmodule
```

Diff:
```diff
diff --git a/firrtl-snippets/Memory.mfc.old.sv b/firrtl-snippets/Memory.mfc.sv
index 7511b63d3..5f930e602 100644
--- a/firrtl-snippets/Memory.mfc.old.sv
+++ b/firrtl-snippets/Memory.mfc.sv
@@ -21,11 +21,10 @@ module memory_8x32(
   end // always @(posedge)
   reg [2:0]  _GEN_0;
   reg        _GEN_1;
-  reg        _GEN_2;
   always @(posedge RW0_clk) begin
-    _GEN_0 <= RW0_addr;
-    _GEN_1 <= RW0_en;
-    _GEN_2 <= RW0_wmode;
+    if (RW0_en)
+      _GEN_0 <= RW0_addr;
+    _GEN_1 <= RW0_wmode;
     if (RW0_en & RW0_wmode)
       Memory[RW0_addr] <= RW0_wdata;
   end // always @(posedge)
```
